// Cursor
const cur=document.getElementById('cur'),curR=document.getElementById('curR');
document.addEventListener('mousemove',e=>{
  cur.style.cssText=`left:${e.clientX-6}px;top:${e.clientY-6}px`;
  curR.style.cssText=`left:${e.clientX-18}px;top:${e.clientY-18}px`;
});
document.querySelectorAll('a,button,.mcard').forEach(el=>{
  el.addEventListener('mouseenter',()=>{curR.style.transform='scale(1.8)';curR.style.borderColor='var(--red)'});
  el.addEventListener('mouseleave',()=>{curR.style.transform='scale(1)';curR.style.borderColor='var(--gold)'});
});
window.addEventListener('scroll',()=>document.getElementById('nav').classList.toggle('scrolled',scrollY>60));

// Floating emojis
const emos=['🍔','🍟','🥩','🍗','🌮','🥘','🍕','🥪','🍜','🧆','🥗','🍱','🥓','🧀','🫕'];
const fc=document.getElementById('floats');
for(let i=0;i<20;i++){
  const e=document.createElement('div');e.className='fe';
  e.textContent=emos[i%emos.length];
  e.style.cssText=`left:${Math.random()*100}%;font-size:${1+Math.random()*1.4}rem;animation-duration:${10+Math.random()*14}s;animation-delay:${-Math.random()*14}s`;
  fc.appendChild(e);
}

