const cats=['all','burgers','meals','fries','snacks','drinks'];
const labels={all:'All Items',burgers:'🍔 Burgers',meals:'🍛 Meals',fries:'🍟 Fries',snacks:'🥟 Snacks',drinks:'🥤 Drinks'};
let cart=0;
const tabsEl=document.getElementById('tabs');
const grid=document.getElementById('mgrid');

cats.forEach((c,i)=>{
  const b=document.createElement('button');
  b.className='tab'+(i===0?' active':'');
  b.textContent=labels[c];
  b.onclick=()=>filterMenu(c,b);
  tabsEl.appendChild(b);
});

function filterMenu(cat,btn){
  document.querySelectorAll('.tab').forEach(t=>t.classList.remove('active'));
  btn.classList.add('active');
  renderMenu(cat==='all'?menu:menu.filter(m=>m.cat===cat));
}

function renderMenu(items){
  grid.innerHTML='';
  items.forEach((item,i)=>{
    const d=document.createElement('div');
    d.className='mcard';d.style.animationDelay=(i*.055)+'s';
    const bdgs=[];
    if(item.top) bdgs.push(`<span class="bdg bdg-top">${item.top}</span>`);
    if(item.deal) bdgs.push(`<span class="bdg bdg-deal">${item.deal}</span>`);
    bdgs.push(`<span class="bdg bdg-cat">${item.cat}</span>`);
    const rHtml=item.rating?`<div class="card-rating"><span class="star">★</span> ${item.rating}</div>`:'';
    const pHtml=item.orig
      ?`<div class="prices"><span class="p-orig">${item.orig}</span><span class="p-now">${item.price}</span></div>`
      :`<div class="prices"><span class="p-now">${item.price}</span></div>`;
    d.innerHTML=`
      <div class="card-img-wrap">
        <img class="card-img" src="${item.img}" alt="${item.name}" loading="lazy"
          onerror="this.parentElement.innerHTML='<div style=height:165px;background:radial-gradient(circle,rgba(243,156,18,.08),transparent);display:flex;align-items:center;justify-content:center;font-size:4rem>🍽️</div>'">
      </div>
      <div class="card-body">
        <div class="badges">${bdgs.join('')}</div>
        <div class="card-name">${item.name}</div>
        <div class="card-desc">${item.desc}</div>
        ${rHtml}
        <div class="card-footer">${pHtml}<button class="add" onclick="addCart('${item.name.replace(/'/g,"\\'")}')">+</button></div>
      </div>`;
    grid.appendChild(d);
  });
}
renderMenu(menu);

function addCart(name){
  cart++;
  document.getElementById('cn').textContent=cart;
  document.getElementById('cp').classList.add('on');
  const t=document.getElementById('toast');
  t.textContent='🛒 '+name+' added!';
  t.classList.add('show');
  setTimeout(()=>t.classList.remove('show'),2500);
}

