const rt=document.getElementById('revTrack');
[...reviews,...reviews].forEach(r=>{
  const c=document.createElement('div');c.className='rcard';
  c.innerHTML=`<div class="rcard-stars">${'★'.repeat(r.stars)}</div><div class="rcard-text">"${r.text}"</div><div class="rcard-author">${r.author}</div><div class="rcard-item">Ordered: ${r.item}</div>`;
  rt.appendChild(c);
});

// Scroll reveal
const obs=new IntersectionObserver(entries=>entries.forEach(e=>{if(e.isIntersecting)e.target.classList.add('in')}),{threshold:.1});
document.querySelectorAll('.rv').forEach(el=>obs.observe(el));